head.b:skin:
/* 
  SMM Panel Theme 
  Dark Mode & Glassmorphism
*/
:root {
  --bg-color: #0f172a;
  --card-bg: #1e293b;
  --text-primary: #f8fafc;
  --text-secondary: #94a3b8;
  --accent: #6366f1;
  --accent-hover: #4f46e5;
  --success: #10b981;
  --warning: #f59e0b;
  --danger: #ef4444;
  --glass-bg: rgba(30, 41, 59, 0.7);
  --glass-border: rgba(255, 255, 255, 0.08);
  --sidebar-width: 260px;
}

* { box-sizing: border-box; margin: 0; padding: 0; font-family: 'Inter', sans-serif; }
body { background-color: var(--bg-color); color: var(--text-primary); min-height: 100vh; overflow-x: hidden; }

/* Layout */
#app { display: flex; min-height: 100vh; }
.sidebar {
  width: var(--sidebar-width);
  background: var(--card-bg);
  border-right: 1px solid var(--glass-border);
  position: fixed;
  height: 100vh;
  padding: 20px;
  transition: transform 0.3s ease;
  z-index: 50;
}
.main-content {
  flex: 1;
  margin-left: var(--sidebar-width);
  padding: 30px;
  transition: margin-left 0.3s ease;
}

/* Mobile */
@media (max-width: 768px) {
  .sidebar { transform: translateX(-100%); }
  .sidebar.active { transform: translateX(0); }
  .main-content { margin-left: 0; padding: 15px; }
  .mobile-menu-btn { display: block !important; }
}

/* Components */
.logo { font-size: 24px; font-weight: 700; color: var(--accent); margin-bottom: 40px; display: flex; align-items: center; gap: 10px; }
.nav-item {
  display: flex; align-items: center; gap: 12px;
  padding: 12px 15px;
  color: var(--text-secondary);
  text-decoration: none;
  border-radius: 12px;
  margin-bottom: 5px;
  transition: all 0.2s;
  cursor: pointer;
}
.nav-item:hover, .nav-item.active { background: rgba(99, 102, 241, 0.1); color: var(--accent); }
.nav-item i { width: 20px; text-align: center; }

.card {
  background: var(--card-bg);
  border: 1px solid var(--glass-border);
  border-radius: 16px;
  padding: 24px;
  margin-bottom: 24px;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
}

.btn {
  background: var(--accent);
  color: white;
  border: none;
  padding: 12px 24px;
  border-radius: 8px;
  cursor: pointer;
  font-weight: 500;
  transition: background 0.2s;
  display: inline-flex; align-items: center; justify-content: center; gap: 8px;
}
.btn:hover { background: var(--accent-hover); }
.btn-block { width: 100%; }
.btn-danger { background: var(--danger); }
.btn-success { background: var(--success); }
.btn-sm { padding: 6px 12px; font-size: 12px; }

.form-group { margin-bottom: 20px; }
.form-label { display: block; margin-bottom: 8px; color: var(--text-secondary); font-size: 14px; }
.form-control {
  width: 100%;
  background: rgba(15, 23, 42, 0.5);
  border: 1px solid var(--glass-border);
  color: white;
  padding: 12px;
  border-radius: 8px;
  outline: none;
  transition: border-color 0.2s;
}
.form-control:focus { border-color: var(--accent); }
select.form-control { appearance: none; background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%2394a3b8' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e"); background-repeat: no-repeat; background-position: right 1rem center; background-size: 1em; }

/* Stats Grid */
.stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 24px; margin-bottom: 30px; }
.stat-card { background: linear-gradient(135deg, rgba(30,41,59,0.8), rgba(30,41,59,0.4)); border: 1px solid var(--glass-border); padding: 24px; border-radius: 16px; position: relative; overflow: hidden; }
.stat-card::before { content: ''; position: absolute; top: 0; left: 0; width: 4px; height: 100%; background: var(--accent); }
.stat-value { font-size: 28px; font-weight: 700; margin: 10px 0 5px; }
.stat-label { color: var(--text-secondary); font-size: 14px; }

/* Tables */
.table-container { overflow-x: auto; }
table { width: 100%; border-collapse: collapse; }
th { text-align: left; padding: 16px; color: var(--text-secondary); font-weight: 500; border-bottom: 1px solid var(--glass-border); }
td { padding: 16px; border-bottom: 1px solid var(--glass-border); color: var(--text-primary); }
.badge { padding: 4px 10px; border-radius: 20px; font-size: 12px; font-weight: 500; }
.badge-pending { background: rgba(245, 158, 11, 0.1); color: var(--warning); }
.badge-completed, .badge-approved { background: rgba(16, 185, 129, 0.1); color: var(--success); }
.badge-cancelled, .badge-rejected { background: rgba(239, 68, 68, 0.1); color: var(--danger); }

/* Auth Pages */
.auth-container { display: flex; align-items: center; justify-content: center; min-height: 100vh; padding: 20px; }
.auth-card { width: 100%; max-width: 400px; }

/* Toast */
.toast-container { position: fixed; bottom: 20px; right: 20px; z-index: 100; display: flex; flex-direction: column; gap: 10px; }
.toast { background: var(--card-bg); border: 1px solid var(--glass-border); padding: 16px 20px; border-radius: 8px; display: flex; align-items: center; gap: 12px; box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1); animation: slideIn 0.3s ease; min-width: 300px; }
.toast-success { border-left: 4px solid var(--success); }
.toast-error { border-left: 4px solid var(--danger); }
@keyframes slideIn { from { transform: translateX(100%); opacity: 0; } to { transform: translateX(0); opacity: 1; } }

/* Loading */
.loader { border: 3px solid rgba(255,255,255,0.1); border-radius: 50%; border-top: 3px solid var(--accent); width: 24px; height: 24px; animation: spin 1s linear infinite; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
.page-loader { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: var(--bg-color); display: flex; justify-content: center; align-items: center; z-index: 999; }

.hidden { display: none !important; }
.mobile-menu-btn { display: none; position: fixed; top: 20px; right: 20px; z-index: 60; background: var(--card-bg); border: 1px solid var(--glass-border); color: white; padding: 10px; border-radius: 8px; cursor: pointer; }

/* Tabs */
.tabs { display: flex; gap: 10px; margin-bottom: 20px; border-bottom: 1px solid var(--glass-border); padding-bottom: 10px; }
.tab { padding: 8px 16px; cursor: pointer; border-radius: 6px; color: var(--text-secondary); }
.tab.active { background: var(--accent); color: white; }

body.script:
import { initializeApp } from "https://www.gstatic.com/firebasejs/9.23.0/firebase-app.js";
import { getAuth, createUserWithEmailAndPassword, signInWithEmailAndPassword, signOut, onAuthStateChanged } from "https://www.gstatic.com/firebasejs/9.23.0/firebase-auth.js";
import { getFirestore, collection, addDoc, getDocs, doc, getDoc, updateDoc, deleteDoc, query, where, orderBy, onSnapshot, runTransaction, setDoc, serverTimestamp } from "https://www.gstatic.com/firebasejs/9.23.0/firebase-firestore.js";

// --- CONFIGURATION ---
const firebaseConfig = {
  apiKey: "AIzaSyBq7btj6m0_GQ_3e05jtZuxdWECypxuF5Y",
  authDomain: "smmzm-ad329.firebaseapp.com",
  projectId: "smmzm-ad329",
  storageBucket: "smmzm-ad329.firebasestorage.app",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const db = getFirestore(app);

// --- STATE ---
let currentUser = null;
let userProfile = null;
let services = [];

// --- ROUTER ---
const routes = {
  'login': renderLogin,
  'register': renderRegister,
  'dashboard': renderDashboard,
  'new-order': renderNewOrder,
  'orders': renderOrders,
  'add-funds': renderAddFunds,
  'admin': renderAdmin
};

async function router() {
  const hash = window.location.hash.slice(1) || 'login';
  const page = hash.split('?')[0]; // Handle query params if needed

  // Auth Guard
  if (!currentUser && page !== 'login' && page !== 'register') {
    window.location.hash = 'login';
    return;
  }
  if (currentUser && (page === 'login' || page === 'register')) {
    window.location.hash = 'dashboard';
    return;
  }

  // Render
  const renderer = routes[page] || render404;

  // Update Sidebar Active State
  document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
  const activeLink = document.querySelector(`[href="#${page}"]`);
  if (activeLink) activeLink.classList.add('active');

  // Hide sidebar on mobile nav
  if (window.innerWidth <= 768) {
    document.getElementById('sidebar').classList.remove('active');
  }

  await renderer();
}

window.addEventListener('hashchange', router);
window.addEventListener('load', () => {
  // Listen for Auth State
  onAuthStateChanged(auth, async (user) => {
    currentUser = user;
    if (user) {
      // Fetch Profile
      const docRef = doc(db, "users", user.uid);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        userProfile = docSnap.data();
      }
      renderSidebar();
    } else {
      userProfile = null;
      document.getElementById('sidebar').style.display = 'none';
      document.getElementById('main-content').style.marginLeft = '0';
    }

    document.getElementById('page-loader').classList.add('hidden');
    router();
  });
});

// --- UI HELPERS ---
function showToast(message, type = 'success') {
  const container = document.getElementById('toast-container');
  const toast = document.createElement('div');
  toast.className = `toast toast-${type}`;
  toast.innerHTML = `

    ${message}
  `;
  container.appendChild(toast);
  setTimeout(() => toast.remove(), 3000);
}

window.toggleSidebar = () => {
  document.getElementById('sidebar').classList.toggle('active');
};

function renderSidebar() {
  const sidebar = document.getElementById('sidebar');
  const main = document.getElementById('main-content');

  if (!currentUser) {
    sidebar.style.display = 'none';
    main.style.marginLeft = '0';
    return;
  }

  sidebar.style.display = 'block';
  if (window.innerWidth > 768) main.style.marginLeft = '260px';

  const isAdmin = userProfile?.role === 'admin';

  document.getElementById('nav-menu').innerHTML = `
     Dashboard
     New Order
     Order History
     Add Funds
    ${isAdmin ? ` Admin Panel` : ''}

 Logout
  `;
}

window.logout = () => {
  signOut(auth).then(() => showToast('Logged out'));
};

// --- PAGES ---

function renderLogin() {
  document.getElementById('sidebar').style.display = 'none';
  document.getElementById('main-content').style.marginLeft = '0';
  document.getElementById('main-content').innerHTML = `





Login



            Email




            Password


          Login


            No account? Register




  `;

  document.getElementById('login-form').onsubmit = async (e) => {
    e.preventDefault();
    const email = document.getElementById('email').value;
    const password = document.getElementById('password').value;
    try {
      await signInWithEmailAndPassword(auth, email, password);
      showToast('Welcome back!');
    } catch (err) {
      showToast(err.message, 'error');
    }
  };
}

function renderRegister() {
  document.getElementById('sidebar').style.display = 'none';
  document.getElementById('main-content').style.marginLeft = '0';
  document.getElementById('main-content').innerHTML = `





Register



            Email




            Password


          Register


            Have an account? Login




  `;

  document.getElementById('register-form').onsubmit = async (e) => {
    e.preventDefault();
    const email = document.getElementById('reg-email').value;
    const password = document.getElementById('reg-password').value;
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      // Create User Doc
      await setDoc(doc(db, "users", cred.user.uid), {
        uid: cred.user.uid,
        email: email,
        balance: 0,
        role: 'user',
        createdAt: serverTimestamp()
      });
      showToast('Account created!');
    } catch (err) {
      showToast(err.message, 'error');
    }
  };
}

function render404() {
  document.getElementById('main-content').innerHTML = `
404 - Page Not Found`;
}

async function renderDashboard() {
  // Refresh profile to get latest balance
  const docRef = doc(db, "users", currentUser.uid);
  const docSnap = await getDoc(docRef);
  userProfile = docSnap.data();

  // Get Order Stats
  const q = query(collection(db, "orders"), where("userId", "==", currentUser.uid));
  const querySnapshot = await getDocs(q);
  const totalOrders = querySnapshot.size;
  let totalSpent = 0;
  querySnapshot.forEach(doc => totalSpent += doc.data().price);

  document.getElementById('main-content').innerHTML = `

Dashboard





Current Balance

$${userProfile.balance.toFixed(2)}
        Add Funds




Total Orders

${totalOrders}




Total Spent

$${totalSpent.toFixed(2)}






Recent News

Welcome to the best SMM Panel. We support MTN and Airtel Mobile Money payments.

  `;
}

async function renderNewOrder() {
  // Fetch Services
  const q = query(collection(db, "services"), orderBy("category"));
  const querySnapshot = await getDocs(q);
  services = [];
  querySnapshot.forEach(doc => services.push({id: doc.id, ...doc.data()}));

  // Group by Category
  const categories = [...new Set(services.map(s => s.category))];

  document.getElementById('main-content').innerHTML = `

New Order





          Category

            Select Category
            ${categories.map(c => `${c}`).join('')}





          Service

            Select Service








          Link





          Quantity






          Total Charge



        Submit Order


  `;

  // Logic
  const catSelect = document.getElementById('category-select');
  const servSelect = document.getElementById('service-select');
  const qtyInput = document.getElementById('quantity');
  const chargeInput = document.getElementById('charge');
  let selectedService = null;

  catSelect.addEventListener('change', () => {
    const cat = catSelect.value;
    servSelect.innerHTML = 'Select Service';
    servSelect.disabled = !cat;

    if (cat) {
      const catServices = services.filter(s => s.category === cat);
      catServices.forEach(s => {
        servSelect.innerHTML += `${s.name} - $${s.price}/1k`;
      });
    }
  });

  servSelect.addEventListener('change', () => {
    const sId = servSelect.value;
    selectedService = services.find(s => s.id === sId);
    if (selectedService) {
      document.getElementById('qty-limits').innerText = `Min: ${selectedService.min} | Max: ${selectedService.max}`;
      calculatePrice();
    }
  });

  qtyInput.addEventListener('input', calculatePrice);

  function calculatePrice() {
    if (!selectedService || !qtyInput.value) return;
    const qty = parseInt(qtyInput.value);
    const price = (qty / 1000) * selectedService.price;
    chargeInput.value = `$${price.toFixed(4)}`;
  }

  document.getElementById('order-form').onsubmit = async (e) => {
    e.preventDefault();
    if (!selectedService) return showToast('Select a service', 'error');

    const qty = parseInt(qtyInput.value);
    const link = document.getElementById('link').value;
    const price = (qty / 1000) * selectedService.price;

    if (qty < selectedService.min || qty > selectedService.max) {
      return showToast(`Quantity must be between ${selectedService.min} and ${selectedService.max}`, 'error');
    }

    if (userProfile.balance < price) {
      return showToast('Insufficient balance', 'error');
    }

    try {
      // Run Transaction to deduct balance and create order securely
      await runTransaction(db, async (transaction) => {
        const userRef = doc(db, "users", currentUser.uid);
        const userDoc = await transaction.get(userRef);

        if (!userDoc.exists()) throw "User does not exist!";
        const newBalance = userDoc.data().balance - price;

        if (newBalance < 0) throw "Insufficient balance!";

        transaction.update(userRef, { balance: newBalance });

        const newOrderRef = doc(collection(db, "orders"));
        transaction.set(newOrderRef, {
          orderId: newOrderRef.id,
          userId: currentUser.uid,
          serviceId: selectedService.id,
          serviceName: selectedService.name,
          link: link,
          quantity: qty,
          price: price,
          status: 'Pending',
          createdAt: serverTimestamp()
        });
      });

      showToast('Order placed successfully!');
      window.location.hash = 'orders';
    } catch (err) {
      showToast(err.toString(), 'error');
    }
  };
}

async function renderOrders() {
  const q = query(collection(db, "orders"), where("userId", "==", currentUser.uid), orderBy("createdAt", "desc"));
  const querySnapshot = await getDocs(q);

  let html = `

Order History






            ID
            Service
            Link
            Qty
            Charge
            Status



  `;

  querySnapshot.forEach(doc => {
    const o = doc.data();
    const statusClass = o.status === 'Completed' ? 'badge-completed' : (o.status === 'Cancelled' ? 'badge-cancelled' : 'badge-pending');
    html += `


        ${o.orderId.slice(0, 8)} 
        ${o.serviceName || 'Service ' + o.serviceId}
        Link
        ${o.quantity}
        $${o.price.toFixed(3)}
        ${o.status}

    `;
  });

  html += ``;
  document.getElementById('main-content').innerHTML = html;
}

async function renderAddFunds() {
  document.getElementById('main-content').innerHTML = `

Add Funds



Mobile Money Payment

Send money to one of the numbers below and fill the form.





          MTN Mobile Money

          096XXXXXXX

          Name: SMM Admin



          Airtel Money

          097XXXXXXX

          Name: SMM Admin






          Network

            MTN Mobile Money
            Airtel Money




          Amount ($)




          Sender Phone Number




          Transaction ID


        Submit Payment




Payment History

Loading...
  `;

  // Load History
  const q = query(collection(db, "payments"), where("userId", "==", currentUser.uid), orderBy("createdAt", "desc"));
  const querySnapshot = await getDocs(q);
  let histHtml = `

IDMethodAmountStatus`;
  querySnapshot.forEach(doc => {
    const p = doc.data();
    const statusClass = p.status === 'Approved' ? 'badge-approved' : (p.status === 'Rejected' ? 'badge-rejected' : 'badge-pending');
    histHtml += `
${p.transactionId}${p.network}$${p.amount}${p.status}`;
  });
  histHtml += ``;
  document.getElementById('payment-history').innerHTML = histHtml;

  // Submit Handler
  document.getElementById('payment-form').onsubmit = async (e) => {
    e.preventDefault();
    try {
      await addDoc(collection(db, "payments"), {
        userId: currentUser.uid,
        network: document.getElementById('pay-network').value,
        amount: parseFloat(document.getElementById('pay-amount').value),
        phone: document.getElementById('pay-phone').value,
        transactionId: document.getElementById('pay-trx').value,
        status: 'Pending',
        createdAt: serverTimestamp()
      });
      showToast('Payment submitted for review');
      renderAddFunds(); // Reload
    } catch (err) {
      showToast(err.message, 'error');
    }
  };
}

// --- ADMIN PANEL ---
async function renderAdmin() {
  if (userProfile.role !== 'admin') {
    return showToast('Access Denied', 'error');
  }

  document.getElementById('main-content').innerHTML = `

Admin Panel



Payments

Orders

Services


Loading...
  `;

  window.switchAdminTab = (tab) => {
    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
    event.target.classList.add('active');
    if (tab === 'payments') loadAdminPayments();
    if (tab === 'orders') loadAdminOrders();
    if (tab === 'services') loadAdminServices();
  };

  loadAdminPayments();
}

async function loadAdminPayments() {
  const q = query(collection(db, "payments"), orderBy("createdAt", "desc"));
  const querySnapshot = await getDocs(q);

  let html = `

UserTrx IDAmountStatusAction`;

  querySnapshot.forEach(docSnap => {
    const p = docSnap.data();
    const id = docSnap.id;
    if (p.status === 'Pending') {
      html += `


          ${p.userId.slice(0,5)}...
          ${p.transactionId}
          $${p.amount}
          ${p.status}

            ✓
            ✗


      `;
    }
  });
  html += ``;
  document.getElementById('admin-content').innerHTML = html;
}

window.approvePayment = async (paymentId, userId, amount) => {
  if (!confirm('Approve this payment?')) return;
  try {
    await runTransaction(db, async (transaction) => {
      const userRef = doc(db, "users", userId);
      const payRef = doc(db, "payments", paymentId);

      const userDoc = await transaction.get(userRef);
      if (!userDoc.exists()) throw "User not found";

      const newBalance = (userDoc.data().balance || 0) + amount;
      transaction.update(userRef, { balance: newBalance });
      transaction.update(payRef, { status: 'Approved' });
    });
    showToast('Payment Approved');
    loadAdminPayments();
  } catch (err) {
    showToast(err.message, 'error');
  }
};

window.rejectPayment = async (paymentId) => {
  if (!confirm('Reject this payment?')) return;
  try {
    await updateDoc(doc(db, "payments", paymentId), { status: 'Rejected' });
    showToast('Payment Rejected');
    loadAdminPayments();
  } catch (err) {
    showToast(err.message, 'error');
  }
};

async function loadAdminOrders() {
  const q = query(collection(db, "orders"), orderBy("createdAt", "desc"));
  const querySnapshot = await getDocs(q);

  let html = `

IDServiceLinkStatusAction`;

  querySnapshot.forEach(docSnap => {
    const o = docSnap.data();
    const id = docSnap.id;
    html += `


        ${o.orderId.slice(0,5)}
        ${o.serviceName}
        ${o.link.slice(0, 15)}...
        ${o.status}


            Set Status
            Pending
            Processing
            Completed
            Cancelled



    `;
  });
  html += ``;
  document.getElementById('admin-content').innerHTML = html;
}

window.updateOrderStatus = async (id, status) => {
  if (!status) return;
  await updateDoc(doc(db, "orders", id), { status: status });
  showToast('Order Updated');
};

async function loadAdminServices() {
  const q = query(collection(db, "services"), orderBy("category"));
  const querySnapshot = await getDocs(q);

  let html = `



Add Service






        Add




NameCategoryPriceAction
  `;

  querySnapshot.forEach(docSnap => {
    const s = docSnap.data();
    html += `
${s.name}${s.category}$${s.price}Del`;
  });
  html += ``;
  document.getElementById('admin-content').innerHTML = html;

  document.getElementById('add-service-form').onsubmit = async (e) => {
    e.preventDefault();
    await addDoc(collection(db, "services"), {
      name: document.getElementById('s-name').value,
      category: document.getElementById('s-cat').value,
      price: parseFloat(document.getElementById('s-price').value),
      min: parseInt(document.getElementById('s-min').value),
      max: parseInt(document.getElementById('s-max').value)
    });
    showToast('Service Added');
    loadAdminServices();
  };
}

window.deleteService = async (id) => {
  if (!confirm('Delete?')) return;
  try {
    await deleteDoc(doc(db, "services", id));
    showToast('Service Deleted');
    loadAdminServices();
  } catch (err) {
    showToast(err.message, 'error');
  }
};
